import './App.css';
import { useState } from 'react';

function App() {
  const [searchTerm, setSearchTerm] = useState('');
  const [cars, setCars] = useState([]);

  const searchCars = async () => {
    if (!searchTerm) return;
    const response = await fetch(`http://localhost:5000/api/cars?s=${searchTerm}`);
    const data = await response.json();
    if (data.Models) {
      setCars(data.Models);
    } else {
      setCars([]);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>Car Finder</h1>
        <div className="search-container">
          <input
            type="text"
            placeholder="Search for car brands..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button onClick={searchCars}>Search</button>
        </div>
      </header>
      <main>
        <div className="cars-container">
          {cars.map((car) => (
            <div key={car.model_id} className="car-card">
              <img src={car.model_img || 'https://via.placeholder.com/200x150?text=Car+Image'} alt={car.model_name} />
              <h3>{searchTerm} - {car.model_name}</h3>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default App;
